import { DarkSectorVault, type DSAEVault } from './dark-atomized-encryption';
import { MeshEngine } from './mesh-engine';
import { type PackedKnot, toBytes, fromBytes, writebackToVFS } from './runtime/packed-knot';
import { type RevSignals } from '../../aeon/src/flow/ProgressiveMeshOrchestrator';

/**
 * DarkSectorSafe -- A "Safety Deposit Box" for the Dark Sector.
 * 
 * Lessons applied:
 * 1. Binary Reassembly: Using Uint8Array concatenation for ~6x speedup.
 * 2. Arbitrary Data Packing: Treating raw bytes as DNA crossings.
 * 3. Topological KV: Mapping keys to disjoint dark matter clusters.
 */
export class DarkSectorSafe {
  private vault: DarkSectorVault;
  private inventory: Map<string, DSAEVault> = new Map();

  constructor(private engine: MeshEngine) {
    this.vault = new DarkSectorVault(engine);
  }

  /**
   * Deposits arbitrary binary data into the safe under a specific key.
   */
  async deposit(key: string, data: Uint8Array, signals: RevSignals): Promise<void> {
    const dsaeVault = await this.vault.encrypt(data, 4, signals);
    this.inventory.set(key, dsaeVault);
  }

  /**
   * Withdraws and reconstructs the data for a given key.
   */
  async withdraw(key: string): Promise<Uint8Array | null> {
    const dsaeVault = this.inventory.get(key);
    if (!dsaeVault) return null;

    try {
      return await this.vault.decrypt(dsaeVault);
    } catch (e) {
      console.error('Failed to reconstruct data from safe:', e);
      return null;
    }
  }

  /**
   * Persists a deposit to a "Safety Deposit Box" file.
   */
  async persist(key: string, filePath: string): Promise<void> {
    const dsaeVault = this.inventory.get(key);
    if (!dsaeVault) throw new Error(`Key ${key} not found in inventory`);

    const data = await this.vault.decrypt(dsaeVault);
    const { writeFile } = await import('node:fs/promises');
    await writeFile(filePath, data);
  }

  /**
   * Liquidates a deposit, stopping its Dark Energy expansion.
   */
  async liquidate(key: string): Promise<void> {
    const dsaeVault = this.inventory.get(key);
    if (dsaeVault) {
      dsaeVault.expansion.stop();
      this.inventory.delete(key);
    }
  }

  /**
   * Returns the current number of active expansions (dimensions of the safe).
   */
  get dimensionCount(): number {
    return this.inventory.size;
  }
}
